local HyperlinkJumpType = HyperlinkJumpType

local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxFriendCtrl:LxBaseCtrl
local LxFriendCtrl = classX("LxFriendCtrl", LxBaseCtrl)

function LxFriendCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxFriendCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxFriendCtrl:InitAfterLoginGame()
    self:InitAfterLoginGameEvents()
    self._isInitAfterLoginGame = true
end

function LxFriendCtrl:InitAfterLoginGameEvents()
    if self._isInitAfterLoginGame then return end
    self:AddEventHandler(EventNames.ROLE_ONLINE_STATE, self.OnRoleOnlineState, self)
end

-- 私聊
function LxFriendCtrl:OnChatPrivate(param)
    param = param or {}
    local panelMgr = MgrCenter.PanelMgr
    local ctrl = panelMgr:GetPanelCtrl(UiNames.Chat)
    if not ctrl then
        ctrl = panelMgr:ShowPanel(UiNames.Chat)
    end

    if param.roleInfo then
        ModuleCenter.Chat:AddPrivateRole(param.roleInfo)
    end

    ctrl:SetParamData({ chatCtrlType = ChatCtrlType.Chat, channel = ChatChannel.Private, privateRoleInfo = param.roleInfo })
    if ctrl:IsPanelReady() then
        ctrl:OnChatPrivate()
    end

    local change, list = ModuleCenter.Chat:GetPrivateRoleIdList()
    if change then
        HandlerCenter.Common:CheckOfflineTimeReq(list)
    end
end

-- 查看玩家
function LxFriendCtrl:OnChatLookAtPlayer(param)
    param = param or {}
    if not param.roleId then
        return
    end
    if ModuleCenter.Login:IsSelf(param.roleId) then
        return
    end

    --HandlerCenter.Role:RoleInfoShowReq(param.roleId)
    ShowPanel(UiNames.RoleInfo, { roleId = param.roleId, msg = param.msg })
end


-- 角色在线状态
function LxFriendCtrl:OnRoleOnlineState(roleMap)
    for roleId, info in pairs(roleMap) do
        ModuleCenter.Chat:SetPrivateRoleInfo(roleId, info)
    end
    FireEvent(EventNames.CHAT_PRIVATE_ONLINE_CHANGE)
end

function LxFriendCtrl:GetRedNum()
    local num = 0
    if CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Friend) then
        num = ModuleCenter.Friend:GetApplyRedNum()
    end
    return num;
end
return LxFriendCtrl
